   1→"use client";
   2→
   3→import { useState, useEffect, useCallback, useRef, useMemo } from "react";
   4→import Link from "next/link";
   5→import IdeaBriefCard from "@/components/IdeaBriefCard";
   6→import GenerateSpecCta from "@/components/GenerateSpecCta";
   7→import BookmarkButton from "@/components/BookmarkButton";
   8→import { Spinner } from "@/components/icons";
   9→import { PlatformIcon } from "@/components/ui";
  10→import { useAuth } from "@/components/AuthProvider";
  11→import { api } from "@/lib/api";
  12→import { normalizeIdeas } from "@/lib/normalize";
  13→import { humanizeText } from "@/lib/humanize";
  14→import {
  15→  trackIdeaViewed,
  16→  trackArchiveFiltered,
  17→  trackUpgradeClicked,
  18→} from "@/lib/analytics";
  19→import type { IdeaBrief, EffortLevel } from "@/lib/types";
  20→
  21→const PAGE_SIZE = 24;
  22→
  23→type Platform = "reddit" | "hn" | "github";
  24→const ALL_PLATFORMS: Platform[] = ["reddit", "hn", "github"];
  25→function isPlatform(value: string): value is Platform {
  26→  return value === "reddit" || value === "hn" || value === "github";
  27→}
  28→
  29→type DateRange = "all" | "7d" | "30d" | "90d";
  30→
  31→const dateRangeOptions: { value: DateRange; label: string }[] = [
  32→  { value: "all", label: "All Time" },
  33→  { value: "7d", label: "7 Days" },
  34→  { value: "30d", label: "30 Days" },
  35→  { value: "90d", label: "90 Days" },
  36→];
  37→
  38→type SortOption = "newest" | "top-scored" | "lowest-effort" | "a-z";
  39→
  40→const sortOptions: { value: SortOption; label: string }[] = [
  41→  { value: "newest", label: "Newest" },
  42→  { value: "top-scored", label: "Top Scored" },
  43→  { value: "lowest-effort", label: "Lowest Effort" },
  44→  { value: "a-z", label: "A → Z" },
  45→];
  46→
  47→const effortOptions: { value: EffortLevel | "all"; label: string }[] = [
  48→  { value: "all", label: "All Efforts" },
  49→  { value: "weekend", label: "Weekend" },
  50→  { value: "week", label: "1 Week" },
  51→  { value: "month", label: "1 Month" },
  52→  { value: "quarter", label: "Quarter+" },
  53→];
  54→
  55→const platformConfig: Record<
  56→  Platform,
  57→  { letter: string; label: string; activeColor: string }
  58→> = {
  59→  reddit: {
  60→    letter: "R",
  61→    label: "Reddit",
  62→    activeColor:
  63→      "bg-orange-100 text-orange-800 border-orange-400 dark:bg-orange-900 dark:text-orange-200 dark:border-orange-600",
  64→  },
  65→  hn: {
  66→    letter: "Y",
  67→    label: "Hacker News",
  68→    activeColor:
  69→      "bg-orange-100 text-orange-800 border-orange-400 dark:bg-orange-900 dark:text-orange-200 dark:border-orange-600",
  70→  },
  71→  github: {
  72→    letter: "G",
  73→    label: "GitHub",
  74→    activeColor:
  75→      "bg-gray-200 text-gray-800 border-gray-500 dark:bg-gray-700 dark:text-gray-200 dark:border-gray-500",
  76→  },
  77→};
  78→
  79→function getScoreCircleColor(score: number) {
  80→  if (score >= 80) return "bg-green-500";
  81→  if (score >= 60) return "bg-blue-500";
  82→  if (score >= 40) return "bg-yellow-500";
  83→  return "bg-gray-400";
  84→}
  85→
  86→function getEffortLabel(effort: EffortLevel) {
  87→  const labels: Record<EffortLevel, string> = {
  88→    weekend: "Weekend",
  89→    week: "1 Week",
  90→    month: "1 Month",
  91→    quarter: "Quarter+",
  92→  };
  93→  return labels[effort] || effort;
  94→}
  95→
  96→function getEffortBadgeColor(effort: EffortLevel) {
  97→  const colors: Record<EffortLevel, string> = {
  98→    weekend: "bg-emerald-100 text-emerald-800 dark:bg-emerald-900 dark:text-emerald-200",
  99→    week: "bg-blue-100 text-blue-800 dark:bg-blue-900 dark:text-blue-200",
 100→    month: "bg-orange-100 text-orange-800 dark:bg-orange-900 dark:text-orange-200",
 101→    quarter: "bg-red-100 text-red-800 dark:bg-red-900 dark:text-red-200",
 102→  };
 103→  return colors[effort] || "bg-gray-100 text-gray-800 dark:bg-gray-700 dark:text-gray-200";
 104→}
 105→
 106→function relativeTime(dateStr: string): string {
 107→  const now = Date.now();
 108→  const then = new Date(dateStr).getTime();
 109→  const diffMs = now - then;
 110→  const diffMins = Math.floor(diffMs / 60000);
 111→  if (diffMins < 1) return "just now";
 112→  if (diffMins < 60) return `${diffMins}m ago`;
 113→  const diffHours = Math.floor(diffMins / 60);
 114→  if (diffHours < 24) return `${diffHours}h ago`;
 115→  const diffDays = Math.floor(diffHours / 24);
 116→  if (diffDays < 7) return `${diffDays}d ago`;
 117→  const diffWeeks = Math.floor(diffDays / 7);
 118→  if (diffWeeks < 5) return `${diffWeeks}w ago`;
 119→  const diffMonths = Math.floor(diffDays / 30);
 120→  if (diffMonths < 12) return `${diffMonths}mo ago`;
 121→  const diffYears = Math.floor(diffDays / 365);
 122→  return `${diffYears}y ago`;
 123→}
 124→
 125→function MiniPlatformBadge({ platform }: { platform: Platform }) {
 126→  return <PlatformIcon platform={platform} size="sm" />;
 127→}
 128→
 129→function SourceToggle({
 130→  platform,
 131→  active,
 132→  onToggle,
 133→}: {
 134→  platform: Platform;
 135→  active: boolean;
 136→  onToggle: () => void;
 137→}) {
 138→  const config = platformConfig[platform];
 139→  return (
 140→    <button
 141→      type="button"
 142→      onClick={onToggle}
 143→      aria-pressed={active}
 144→      className={`inline-flex items-center gap-1.5 px-2.5 py-1.5 rounded-md border text-xs font-medium transition-colors ${
 145→        active
 146→          ? config.activeColor
 147→          : "bg-gray-100 text-gray-400 border-gray-200 dark:bg-gray-800 dark:text-gray-500 dark:border-gray-700"
 148→      }`}
 149→    >
 150→      <PlatformIcon platform={platform} size="sm" />
 151→      <span className="hidden sm:inline">{config.label}</span>
 152→    </button>
 153→  );
 154→}
 155→
 156→function dateRangeToFromTo(range: DateRange): { from?: string; to?: string } {
 157→  if (range === "all") return {};
 158→  const now = new Date();
 159→  const to = now.toISOString();
 160→  const daysMap: Record<string, number> = { "7d": 7, "30d": 30, "90d": 90 };
 161→  const days = daysMap[range];
 162→  const from = new Date(now.getTime() - days * 86400000).toISOString();
 163→  return { from, to };
 164→}
