 270→export default function ArchivePage() {
 271→  const [searchInput, setSearchInput] = useState("");
 272→  const [searchQuery, setSearchQuery] = useState("");
 273→  const [sortBy, setSortBy] = useState<SortOption>("newest");
 274→  const [effortFilter, setEffortFilter] = useState<EffortLevel | "all">("all");
 275→  const [minScoreInput, setMinScoreInput] = useState(0);
 276→  const [minScore, setMinScore] = useState(0);
 277→  const [dateRange, setDateRange] = useState<DateRange>("all");
 278→  const [selectedSources, setSelectedSources] = useState<Set<Platform>>(
 279→    () => new Set(ALL_PLATFORMS)
 280→  );
 281→  const [allIdeas, setAllIdeas] = useState<IdeaBrief[]>([]);
 282→  const [loading, setLoading] = useState(true);
 283→  const [loadingMore, setLoadingMore] = useState(false);
 284→  const [error, setError] = useState<string | null>(null);
 285→  const [total, setTotal] = useState(0);
 286→  const [page, setPage] = useState(1);
 287→  const [hasMore, setHasMore] = useState(true);
 288→  const [selectedIdea, setSelectedIdea] = useState<IdeaBrief | null>(null);
 289→  const [fetchKey, setFetchKey] = useState(0);
 290→  const [preview, setPreview] = useState(false);
 291→  const [savedIdeaIds, setSavedIdeaIds] = useState<Set<string>>(new Set());
 292→  const [showSavedOnly, setShowSavedOnly] = useState(false);
 293→  const [specUsage, setSpecUsage] = useState<{ used: number; limit: number } | null>(null);
 294→  const modalRef = useRef<HTMLDivElement>(null);
 295→  const triggerRef = useRef<HTMLElement | null>(null);
 296→  const { isAuthenticated, user } = useAuth();
 297→
 298→  // Fetch saved idea IDs for the logged-in user
 299→  useEffect(() => {
 300→    if (!isAuthenticated) {
 301→      setSavedIdeaIds(new Set());
 302→      return;
 303→    }
 304→    let cancelled = false;
 305→    async function fetchSaved() {
 306→      try {
 307→        const saved = await api.getSavedIdeas();
 308→        if (cancelled) return;
 309→        const normalized = normalizeIdeas(saved);
 310→        setSavedIdeaIds(new Set(normalized.map((idea) => idea.id)));
 311→      } catch {
 312→        // Silently fail — bookmark state is non-critical
 313→      }
 314→    }
 315→    fetchSaved();
 316→    return () => { cancelled = true; };
 317→  }, [isAuthenticated]);
 318→
 319→  // Fetch spec generation usage for the logged-in user
 320→  useEffect(() => {
 321→    if (!isAuthenticated) return;
 322→    api.getSpecUsage().then(setSpecUsage).catch(() => {});
 323→  }, [isAuthenticated]);
 324→
 325→  // Callback for toggling a saved idea
 326→  const handleToggleSave = useCallback((ideaId: string, saved: boolean) => {
 327→    setSavedIdeaIds((prev) => {
 328→      const next = new Set(prev);
 329→      if (saved) {
 330→        next.add(ideaId);
 331→      } else {
 332→        next.delete(ideaId);
 333→      }
 334→      return next;
 335→    });
 336→  }, []);
 337→
 338→  // Debounce search input
 339→  useEffect(() => {
 340→    const timer = setTimeout(() => setSearchQuery(searchInput), 300);
 341→    return () => clearTimeout(timer);
 342→  }, [searchInput]);
 343→
 344→  // Debounce minScore slider
 345→  useEffect(() => {
 346→    const timer = setTimeout(() => setMinScore(minScoreInput), 500);
 347→    return () => clearTimeout(timer);
 348→  }, [minScoreInput]);
 349→
 350→  // Derive server params from server-side filters
 351→  const serverParams = useMemo(() => {
 352→    const params: {
 353→      effort?: EffortLevel;
 354→      minScore?: number;
 355→      from?: string;
 356→      to?: string;
 357→      sort?: string;
 358→    } = {};
 359→    if (effortFilter !== "all") params.effort = effortFilter;
 360→    if (minScore > 0) params.minScore = minScore;
 361→    const { from, to } = dateRangeToFromTo(dateRange);
 362→    if (from) params.from = from;
 363→    if (to) params.to = to;
 364→    if (sortBy !== "newest") params.sort = sortBy;
 365→    return params;
 366→  }, [effortFilter, minScore, dateRange, sortBy]);
 367→
 368→  // Client-side filtering on accumulated ideas (search + source + saved)
 369→  const filteredIdeas = useMemo(() => {
 370→    let results = allIdeas;
 371→    if (showSavedOnly) {
 372→      results = results.filter((idea) => savedIdeaIds.has(idea.id));
 373→    }
 374→    if (searchQuery) {
 375→      const q = searchQuery.toLowerCase();
 376→      results = results.filter(
 377→        (idea) =>
 378→          idea.name.toLowerCase().includes(q) ||
 379→          idea.tagline.toLowerCase().includes(q)
 380→      );
 381→    }
 382→    // Source filter: idea must have at least one source from a selected platform
 383→    // Ideas with no sources are always shown (don't penalize missing metadata)
 384→    if (selectedSources.size < ALL_PLATFORMS.length) {
 385→      results = results.filter((idea) => {
 386→        if (!idea.sources || idea.sources.length === 0) return true;
 387→        return idea.sources.some((s) => isPlatform(s.platform) && selectedSources.has(s.platform));
 388→      });
 389→    }
 390→    return results;
 391→  }, [allIdeas, searchQuery, selectedSources, showSavedOnly, savedIdeaIds]);
 392→
 393→  // Escape key to close modal
 394→  useEffect(() => {
 395→    if (!selectedIdea) return;
 396→    const handleKeyDown = (e: KeyboardEvent) => {
 397→      if (e.key === "Escape") setSelectedIdea(null);
 398→    };
 399→    document.addEventListener("keydown", handleKeyDown);
 400→    return () => document.removeEventListener("keydown", handleKeyDown);
 401→  }, [selectedIdea]);
 402→
 403→  // Lock body scroll while modal is open
 404→  useEffect(() => {
 405→    if (selectedIdea) {
 406→      document.body.style.overflow = "hidden";
 407→    } else {
 408→      document.body.style.overflow = "";
 409→    }
 410→    return () => {
 411→      document.body.style.overflow = "";
 412→    };
 413→  }, [selectedIdea]);
 414→
 415→  const closeModal = useCallback(() => {
 416→    setSelectedIdea(null);
 417→    triggerRef.current?.focus();
 418→  }, []);
 419→
 420→  // Focus trap for archive modal
 421→  useEffect(() => {
 422→    if (!selectedIdea || !modalRef.current) return;
 423→    const modalElement = modalRef.current;
 424→    const focusableSelectors =
 425→      'a[href], button, input, textarea, select, [tabindex]:not([tabindex="-1"])';
 426→    const getFocusable = () =>
 427→      modalElement.querySelectorAll<HTMLElement>(focusableSelectors);
 428→
 429→    // Focus first focusable element in modal
 430→    const focusable = getFocusable();
 431→    if (focusable.length > 0) focusable[0].focus();
 432→
 433→    const handleTabTrap = (e: KeyboardEvent) => {
 434→      if (e.key !== "Tab") return;
 435→      const currentFocusable = getFocusable();
 436→      if (currentFocusable.length === 0) return;
 437→      const first = currentFocusable[0];
 438→      const last = currentFocusable[currentFocusable.length - 1];
 439→      if (e.shiftKey) {
 440→        if (document.activeElement === first) {
 441→          e.preventDefault();
 442→          last.focus();
 443→        }
 444→      } else {
 445→        if (document.activeElement === last) {
 446→          e.preventDefault();
 447→          first.focus();
 448→        }
 449→      }
 450→    };
 451→
 452→    document.addEventListener("keydown", handleTabTrap);
 453→    return () => document.removeEventListener("keydown", handleTabTrap);
 454→  }, [selectedIdea]);
 455→
 456→  // Toggle source platform
 457→  const toggleSource = useCallback((platform: Platform) => {
 458→    setSelectedSources((prev) => {
 459→      const next = new Set(prev);
 460→      if (next.has(platform)) {
 461→        next.delete(platform);
 462→      } else {
 463→        next.add(platform);
 464→      }
 465→      return next;
 466→    });
 467→  }, []);
 468→
 469→  // Initial fetch (page 1) — re-runs when serverParams change
 470→  useEffect(() => {
 471→    let cancelled = false;
 472→    async function fetchInitial() {
 473→      setLoading(true);
 474→      setError(null);
 475→      setAllIdeas([]);
 476→      setPage(1);
 477→      setHasMore(true);
 478→      setPreview(false);
 479→      try {
 480→        const data = await api.getArchive({
 481→          page: 1,
 482→          pageSize: PAGE_SIZE,
 483→          ...serverParams,
 484→        });
 485→        if (cancelled) return;
 486→        const results = normalizeIdeas(data);
 487→        setAllIdeas(results);
 488→        setTotal(data.total ?? results.length);
 489→        setHasMore(data.hasMore ?? results.length >= PAGE_SIZE);
 490→        setPreview(!!(data as unknown as Record<string, unknown>).preview);
 491→        setPage(2);
 492→      } catch (err) {
 493→        if (cancelled) return;
 494→        console.error("Failed to fetch archive:", err);
 495→        setError("Failed to load archive. Please try again later.");
 496→        setAllIdeas([]);
 497→      } finally {
 498→        if (!cancelled) setLoading(false);
 499→      }
 500→    }
 501→    fetchInitial();
 502→    return () => {
 503→      cancelled = true;
 504→    };
 505→  }, [fetchKey, serverParams]);
 506→
 507→  // Load next page
 508→  const loadMore = useCallback(async () => {
 509→    if (loadingMore || !hasMore) return;
 510→    setLoadingMore(true);
 511→    try {
 512→      const data = await api.getArchive({
 513→        page,
 514→        pageSize: PAGE_SIZE,
 515→        ...serverParams,
 516→      });
 517→      const results = normalizeIdeas(data);
 518→      setAllIdeas((prev) => {
 519→        const existingIds = new Set(prev.map((i) => i.id));
 520→        const newItems = results.filter((i) => !existingIds.has(i.id));
 521→        return [...prev, ...newItems];
 522→      });
 523→      setTotal(data.total ?? allIdeas.length + results.length);
 524→      setHasMore(data.hasMore ?? results.length >= PAGE_SIZE);
 525→      setPage((p) => p + 1);
 526→    } catch (err) {
 527→      console.error("Failed to load more ideas:", err);
 528→    } finally {
 529→      setLoadingMore(false);
 530→    }
 531→  }, [page, hasMore, loadingMore, allIdeas.length, serverParams]);
 532→
 533→  // Ref to always have the latest loadMore (avoids stale closures in scroll handler)
 534→  const loadMoreRef = useRef(loadMore);
 535→  loadMoreRef.current = loadMore;
 536→
 537→  // Infinite scroll via scroll handler (disabled in preview mode)
 538→  useEffect(() => {
 539→    if (loading || preview) return;
 540→
 541→    function checkScroll() {
 542→      const scrollBottom = window.innerHeight + window.scrollY;
 543→      const docHeight = document.documentElement.scrollHeight;
 544→      if (scrollBottom >= docHeight - 400) {
 545→        loadMoreRef.current();
 546→      }
 547→    }
 548→
 549→    window.addEventListener("scroll", checkScroll, { passive: true });
 550→    // Check immediately — if content doesn't fill the viewport, load more right away
 551→    checkScroll();
 552→
 553→    return () => window.removeEventListener("scroll", checkScroll);
 554→  }, [loading, loadingMore, preview]);
 555→
 556→  return (
 557→    <main id="main-content" className="mx-auto max-w-6xl px-4 sm:px-6 py-8">
 558→      <header className="mb-8">
 559→        <h1 className="text-3xl font-extrabold tracking-tight text-gray-900 dark:text-white sm:text-4xl mb-2">
 560→          Idea Archive
 561→        </h1>
 562→        <p className="text-gray-600 dark:text-gray-400 text-balance">
 563→          Browse past ideas and find hidden gems
 564→        </p>
 565→      </header>
 566→
 567→      {/* Filters */}
 568→      <div className={`bg-white dark:bg-gray-800 rounded-xl p-4 border border-gray-200 dark:border-gray-700 mb-6 space-y-4 ${preview ? "opacity-50 pointer-events-none select-none" : ""}`} aria-disabled={preview || undefined}>
 569→        {/* Row 1: Search (full width) */}
 570→        <div>
 571→          <label
 572→            htmlFor="search"
 573→            className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1"
 574→          >
 575→            Search
 576→          </label>
 577→          <div className="relative">
 578→            <div className="pointer-events-none absolute inset-y-0 left-0 flex items-center pl-3">
 579→              <svg
 580→                className="h-4 w-4 text-gray-400 dark:text-gray-500"
 581→                fill="none"
 582→                stroke="currentColor"
 583→                viewBox="0 0 24 24"
 584→                aria-hidden="true"
 585→              >
 586→                <path
