 35→} from './utils/persistence';
 36→import type { PhaseStats } from './utils/persistence';
 37→import { db, pipelineRuns } from '../api/db/client';
 38→import { DEFAULT_SIMILARITY_THRESHOLD } from '../analysis/similarity';
 39→import type {
 40→  GenerationDiagnosticsSnapshot,
 41→  PipelineConfig,
 42→  PipelineResult,
 43→  PhaseResult,
 44→  PhaseName,
 45→  ScrapePhaseOutput,
 46→  AnalyzePhaseOutput,
 47→  GeneratePhaseOutput,
 48→  DeliverPhaseOutput,
 49→  PipelineError,
 50→} from './types';
 51→
 52→/** Default scrape lookback window (hours) */
 53→const DEFAULT_HOURS_BACK = 48;
 54→
 55→/** Minimum post frequency for gap analysis to be worth running */
 56→const DEFAULT_MIN_FREQUENCY_FOR_GAP = 2;
 57→
 58→/** Maximum number of briefs to generate per pipeline run */
 59→const DEFAULT_MAX_BRIEFS = 10;
 60→
 61→/** Minimum priority score for a problem to be included in brief generation */
 62→const DEFAULT_MIN_PRIORITY_SCORE = 20;
 63→
 64→/** Heartbeat interval for renewing the pipeline lock while a run is active */
 65→const PIPELINE_LOCK_HEARTBEAT_INTERVAL_MS = 60_000;
 66→
 67→/**
 68→ * Default pipeline configuration
 69→ */
 70→export const DEFAULT_PIPELINE_CONFIG: PipelineConfig = {
 71→  hoursBack: DEFAULT_HOURS_BACK,
 72→  scrapers: {
 73→    reddit: true,
 74→    hn: true,
 75→    twitter: true,
 76→    github: true,
 77→  },
 78→  clusteringThreshold: DEFAULT_SIMILARITY_THRESHOLD,
 79→  minFrequencyForGap: DEFAULT_MIN_FREQUENCY_FOR_GAP,
 80→  maxBriefs: DEFAULT_MAX_BRIEFS,
 81→  minPriorityScore: DEFAULT_MIN_PRIORITY_SCORE,
 82→  dryRun: false,
 83→  verbose: false,
 84→  publishGate: {
 85→    enabled: false,
 86→    confidenceThreshold: 0.85,
 87→  },
 88→};
 89→
 90→/**
 91→ * Generate a unique run ID
 92→ */
 93→export function generateRunId(): string {
 94→  const date = new Date().toISOString().split('T')[0].replace(/-/g, '');
 95→  const rand = crypto.randomBytes(4).toString('hex');
 96→  return `run_${date}_${rand}`;
 97→}
 98→
 99→/**
100→ * Build the final pipeline result
101→ */
102→function buildResult(
103→  runId: string,
104→  startedAt: Date,
105→  config: PipelineConfig,
106→  phases: {
107→    scrape?: PhaseResult<ScrapePhaseOutput>;
108→    analyze?: PhaseResult<AnalyzePhaseOutput>;
109→    generate?: PhaseResult<GeneratePhaseOutput>;
110→    deliver?: PhaseResult<DeliverPhaseOutput>;
111→  },
112→  errors: PipelineError[]
113→): PipelineResult {
114→  const completedAt = new Date();
115→
116→  // Create empty phase results for missing phases
117→  const emptyPhaseResult = <T>(phase: string): PhaseResult<T> => ({
118→    success: false,
119→    data: null,
120→    error: 'Phase not executed',
121→    duration: 0,
122→    phase: phase as PhaseResult<T>['phase'],
123→    timestamp: new Date(),
124→  });
125→
126→  const scrape = phases.scrape || emptyPhaseResult<ScrapePhaseOutput>('scrape');
127→  const analyze = phases.analyze || emptyPhaseResult<AnalyzePhaseOutput>('analyze');
128→  const generate = phases.generate || emptyPhaseResult<GeneratePhaseOutput>('generate');
129→  const deliver = phases.deliver || emptyPhaseResult<DeliverPhaseOutput>('deliver');
130→
131→  return {
132→    runId,
133→    startedAt,
134→    completedAt,
135→    config,
136→    phases: { scrape, analyze, generate, deliver },
137→    stats: {
138→      postsScraped: scrape.data?.totalPosts || 0,
139→      clustersCreated: analyze.data?.clusterCount || 0,
140→      ideasGenerated: generate.data?.briefCount || 0,
141→      emailsSent: deliver.data?.sent || 0,
142→    },
143→    success: deliver.success,
144→    totalDuration: completedAt.getTime() - startedAt.getTime(),
145→    errors,
146→  };
147→}
148→
149→/**
150→ * Check if a phase should be skipped during a resumed run.
151→ * A phase is skipped if it already completed in the previous run
152→ * and falls before the resume point.
153→ */
154→function shouldSkipPhase(
155→  resumePhase: PhaseName | null,
156→  currentPhase: PhaseName
157→): boolean {
158→  if (!resumePhase) return false;
159→  const order: PhaseName[] = ['scrape', 'analyze', 'generate', 'deliver'];
160→  return order.indexOf(currentPhase) < order.indexOf(resumePhase);
161→}
162→
163→/**
164→ * Build a run-level diagnostics snapshot that can be persisted to pipeline_runs.
165→ */
166→function buildGenerationDiagnosticsSnapshot(
167→  generatePhase: PhaseResult<GeneratePhaseOutput>,
168→  apiMetrics: ApiMetricsSummary,
169→): GenerationDiagnosticsSnapshot {
170→  const diagnostics = generatePhase.data?.diagnostics;
171→  const generatedBriefCount = generatePhase.data?.briefCount ?? 0;
172→  const costPerBriefUsd = generatedBriefCount > 0
173→    ? Number((apiMetrics.estimatedCost / generatedBriefCount).toFixed(6))
174→    : null;
175→  const latencyPerBriefMs = generatedBriefCount > 0
176→    ? Math.round(generatePhase.duration / generatedBriefCount)
177→    : null;
178→
179→  if (!diagnostics) {
180→    return {
181→      taxonomyVersion: 'v1',
182→      generatedBriefCount,
183→      qualityPassCount: 0,
184→      qualityFailCount: 0,
185→      qualityPassRate: 0,
186→      fallbackCount: 0,
187→      fallbackRate: 0,
188→      fallbackReasonCounts: {
189→        missing_gap_analysis: 0,
190→        missing_api_key: 0,
191→        single_call_failed: 0,
192→        batch_call_failed: 0,
193→        unknown: 0,
194→      },
195→      qualityFailureReasonCounts: {
196→        placeholder_content: 0,
197→        length_too_short: 0,
198→        list_minimum_not_met: 0,
199→        nested_content_incomplete: 0,
200→        unknown: 0,
201→      },
202→      costPerBriefUsd,
203→      latencyPerBriefMs,
204→    };
205→  }
206→
207→  return {
208→    ...diagnostics,
209→    costPerBriefUsd,
210→    latencyPerBriefMs,
211→  };
212→}
213→
214→/**
215→ * Start periodic lock renewal so long-running pipeline runs keep lock ownership.
216→ * Returns a function that stops the heartbeat timer.
217→ */
218→function startPipelineLockHeartbeat(
219→  runId: string,
220→  logger: ReturnType<typeof createRunLogger>,
221→  onLockLost: () => void,
222→): () => void {
223→  let timer: NodeJS.Timeout | null = null;
224→  let inFlight = false;
225→
226→  const tick = async () => {
227→    if (inFlight) return;
228→    inFlight = true;
229→
230→    try {
231→      const renewed = await extendPipelineLock(runId, PIPELINE_LOCK_TTL_SECONDS);
232→      if (!renewed) {
233→        logger.error(
234→          { runId },
235→          'Pipeline lock ownership lost during run'
236→        );
237→        onLockLost();
238→        if (timer) {
239→          clearInterval(timer);
240→          timer = null;
241→        }
242→      }
243→    } finally {
244→      inFlight = false;
245→    }
246→  };
247→
248→  timer = setInterval(() => {
249→    void tick();
250→  }, PIPELINE_LOCK_HEARTBEAT_INTERVAL_MS);
251→
252→  return () => {
253→    if (timer) {
254→      clearInterval(timer);
255→      timer = null;
256→    }
257→  };
258→}
259→
260→/**
261→ * Run the complete ZeroToShip pipeline
262→ *
263→ * Supports resuming from a previous failed run via `config.resumeRunId`.
264→ * When resuming, completed phase results are loaded from the database and the
265→ * pipeline picks up from the first incomplete phase.
266→ */
267→export async function runPipeline(
268→  config: Partial<PipelineConfig> = {},
269→  preGeneratedRunId?: string
270→): Promise<PipelineResult> {
271→  const fullConfig = { ...DEFAULT_PIPELINE_CONFIG, ...config };
272→  const requestedGenerationMode = fullConfig.generationMode ?? getConfiguredGenerationMode();
273→
274→  // Determine run ID and resume state
275→  let runId: string;
276→  let resumePhase: PhaseName | null = null;
277→
278→  if (fullConfig.resumeRunId) {
279→    const previousStatus = await loadRunStatus(fullConfig.resumeRunId);
280→    if (!previousStatus) {
281→      throw new Error(
282→        `Cannot resume run "${fullConfig.resumeRunId}": run not found in database`
283→      );
284→    }
285→    runId = fullConfig.resumeRunId;
286→    resumePhase = getResumePhase(previousStatus);
287→    if (!resumePhase) {
288→      throw new Error(
289→        `Cannot resume run "${runId}": all phases already completed`
290→      );
291→    }
292→  } else {
293→    runId = preGeneratedRunId || generateRunId();
294→  }
295→
296→  const logger = createRunLogger(runId);
297→
298→  // Clean up stale runs before acquiring the lock (safety net for crashed processes)
299→  await cleanupStaleRuns();
300→
301→  // Acquire distributed lock to prevent concurrent pipeline runs
302→  const lockAcquired = await acquirePipelineLock(runId, PIPELINE_LOCK_TTL_SECONDS);
303→  if (!lockAcquired) {
304→    logger.warn('Pipeline lock is held by another run — skipping');
305→    const now = new Date();
306→    return buildResult(runId, now, fullConfig, {}, [
307→      {
308→        phase: 'scrape',
309→        message: 'Pipeline lock held by another run',
310→        timestamp: now,
311→        recoverable: true,
312→        severity: 'degraded',
313→      },
314→    ]);
315→  }
316→
317→  let lockLost = false;
318→  let stopLockHeartbeat: (() => void) | null = null;
319→  let result: PipelineResult | undefined;
320→
321→  try {
322→  const metrics = new MetricsCollector(runId);
323→  const errors: PipelineError[] = [];
324→
325→  // Reset API metrics at start
326→  resetGlobalMetrics();
327→
328→  const startedAt = new Date();
329→  stopLockHeartbeat = startPipelineLockHeartbeat(runId, logger, () => {
330→    lockLost = true;
331→  });
332→
333→  // Initialize monitoring
334→  initMonitoring();
335→
336→  const abortForLockLoss = (
337→    phase: PhaseName,
338→    phases: {
339→      scrape?: PhaseResult<ScrapePhaseOutput>;
340→      analyze?: PhaseResult<AnalyzePhaseOutput>;
341→      generate?: PhaseResult<GeneratePhaseOutput>;
342→      deliver?: PhaseResult<DeliverPhaseOutput>;
343→    },
344→  ): PipelineResult | null => {
345→    if (!lockLost) return null;
346→
347→    errors.push({
348→      phase,
349→      message: 'Pipeline lock ownership lost during run',
350→      timestamp: new Date(),
351→      recoverable: false,
352→      severity: 'fatal',
353→    });
354→
355→    logger.error({ phase }, 'Aborting pipeline run after lock ownership loss');
356→    return buildResult(runId, startedAt, fullConfig, phases, errors);
357→  };
358→
359→  if (resumePhase) {
360→    logger.info(
361→      { config: fullConfig, resumePhase, requestedGenerationMode },
362→      'Pipeline resuming from previous run'
363→    );
364→  } else {
365→    logger.info({ config: fullConfig, requestedGenerationMode }, 'Pipeline started');
366→    await initRunStatus(runId, fullConfig);
367→  }
368→
369→  // --- Generic phase executor (handles resume, persist, error, lock-loss) ---
370→
371→  type PhaseAccumulator = {
372→    scrape?: PhaseResult<ScrapePhaseOutput>;
373→    analyze?: PhaseResult<AnalyzePhaseOutput>;
374→    generate?: PhaseResult<GeneratePhaseOutput>;
375→    deliver?: PhaseResult<DeliverPhaseOutput>;
376→  };
377→
378→  /**
379→   * Execute a pipeline phase with full boilerplate:
380→   * 1. Resume/skip check — load cached data if the phase already completed
381→   * 2. Run the phase — record metrics
382→   * 3. Persist result + update phase status/stats
383→   * 4. Handle failure — log, push error, capture exception, send alert
384→   * 5. Check for lock loss — abort if lost
385→   *
386→   * Returns `{ phaseResult, earlyReturn }`. If `earlyReturn` is set, the
387→   * caller must return it immediately (fatal failure or lock loss).
388→   */
389→  async function executePhase<T, P extends PhaseName>(opts: {
390→    phase: P;
391→    runner: () => Promise<PhaseResult<T>>;
392→    statsExtractor: (data: T) => NonNullable<PhaseStats[P]>;
393→    metricCountExtractor: (data: T | null) => number;
394→    priorPhases: PhaseAccumulator;
395→  }): Promise<{
396→    phaseResult: PhaseResult<T>;
397→    earlyReturn: PipelineResult | null;
398→  }> {
399→    const { phase, runner, statsExtractor, metricCountExtractor, priorPhases } = opts;
400→    let phaseResult: PhaseResult<T>;
401→
402→    // Step 1: Resume/skip check
403→    if (shouldSkipPhase(resumePhase, phase)) {
404→      const cached = await loadPhaseResult<T>(runId, phase);
405→      if (!cached) {
406→        throw new Error(`Resume failed: could not load persisted ${phase} data for run "${runId}"`);
407→      }
408→      phaseResult = {
409→        success: true,
410→        data: cached,
411→        duration: 0,
412→        phase,
413→        timestamp: new Date(),
414→      };
415→      logger.info(`${phase.charAt(0).toUpperCase() + phase.slice(1)} phase: loaded from persisted data`);
416→    } else {
417→      // Step 2: Run the phase and record metrics
418→      metrics.startPhase(phase);
419→      phaseResult = await runner();
420→      metrics.completePhase(phase, phaseResult.success, metricCountExtractor(phaseResult.data));
421→
422→      // Step 3: Persist result + update status/stats
423→      if (phaseResult.success && phaseResult.data) {
424→        await savePhaseResult(runId, phase, phaseResult.data);
425→        await updatePhaseStatus(runId, phase, 'completed');
426→        await updatePhaseStats(runId, phase, statsExtractor(phaseResult.data));
427→      } else {
428→        await updatePhaseStatus(runId, phase, 'failed');
429→      }
430→    }
431→
432→    // Include this phase's result alongside prior phases for buildResult/abortForLockLoss
433→    const phasesIncludingSelf: PhaseAccumulator = {
434→      ...priorPhases,
435→      [phase]: phaseResult,
436→    };
437→
438→    // Step 4: Handle failure
439→    if (!phaseResult.success || !phaseResult.data) {
440→      const isFatal = phaseResult.severity !== 'degraded';
441→      const phaseLabel = phase.charAt(0).toUpperCase() + phase.slice(1);
442→      logger.error({ severity: phaseResult.severity ?? 'fatal' }, `${phaseLabel} phase failed`);
443→      errors.push({
444→        phase,
445→        message: phaseResult.error || 'Unknown error',
446→        timestamp: new Date(),
447→        recoverable: !isFatal,
448→        severity: phaseResult.severity,
449→      });
450→      captureException(
451→        new Error(phaseResult.error || `${phaseLabel} phase failed`),
452→        { runId, phase, severity: phaseResult.severity }
453→      );
454→      sendPipelineFailureAlert(runId, phase, phaseResult.error || 'Unknown error', phaseResult.severity ?? 'fatal');
455→      if (isFatal) {
456→        const earlyReturn = buildResult(runId, startedAt, fullConfig, phasesIncludingSelf, errors);
457→        return { phaseResult, earlyReturn };
458→      }
459→    }
460→
461→    // Step 5: Check for lock loss
462→    const lockLossResult = abortForLockLoss(phase, phasesIncludingSelf);
463→    if (lockLossResult) {
464→      return { phaseResult, earlyReturn: lockLossResult };
465→    }
466→
467→    return { phaseResult, earlyReturn: null };
468→  }
469→
470→  // Phase 1: Scrape
471→  const { phaseResult: scrapeResult, earlyReturn: scrapeEarly } = await executePhase<ScrapePhaseOutput, 'scrape'>({
472→    phase: 'scrape',
473→    runner: () => runScrapePhase(runId, fullConfig),
474→    statsExtractor: (data) => ({
475→      totalPosts: data.totalPosts,
476→      reddit: data.reddit.count,
477→      hn: data.hn.count,
478→      twitter: data.twitter.count,
479→      github: data.github.count,
480→    }),
481→    metricCountExtractor: (data) => data?.totalPosts || 0,
482→    priorPhases: {},
483→  });
484→  if (scrapeEarly) { result = scrapeEarly; return result; }
485→
486→  // Phase 2: Analyze (requires scrape data)
487→  const { phaseResult: analyzeResult, earlyReturn: analyzeEarly } = await executePhase<AnalyzePhaseOutput, 'analyze'>({
488→    phase: 'analyze',
489→    runner: () => scrapeResult.data?.posts?.length
490→      ? runAnalyzePhase(runId, fullConfig, scrapeResult.data.posts)
491→      : Promise.resolve({ success: false, data: null, error: 'No posts from scrape phase', severity: 'fatal' as const, duration: 0, phase: 'analyze' as const, timestamp: new Date() }),
492→    statsExtractor: (data) => ({
493→      clusterCount: data.clusterCount,
494→      scoredCount: data.scoredCount,
495→      gapAnalysisCount: data.gapAnalysisCount,
496→    }),
497→    metricCountExtractor: (data) => data?.scoredCount || 0,
498→    priorPhases: { scrape: scrapeResult },
499→  });
500→  if (analyzeEarly) { result = analyzeEarly; return result; }
501→
502→  // Phase 3: Generate (requires analyze data)
503→  const { phaseResult: generateResult, earlyReturn: generateEarly } = await executePhase<GeneratePhaseOutput, 'generate'>({
504→    phase: 'generate',
505→    runner: () => analyzeResult.data?.scoredProblems?.length
506→      ? runGeneratePhase(
507→          runId,
508→          fullConfig,
509→          analyzeResult.data.scoredProblems,
510→          analyzeResult.data.gapAnalyses,
511→          requestedGenerationMode,
512→        )
513→      : Promise.resolve({ success: false, data: null, error: 'No scored problems from analyze phase', severity: 'fatal' as const, duration: 0, phase: 'generate' as const, timestamp: new Date() }),
514→    statsExtractor: (data) => ({
515→      briefCount: data.briefCount,
516→    }),
517→    metricCountExtractor: (data) => data?.briefCount || 0,
518→    priorPhases: { scrape: scrapeResult, analyze: analyzeResult },
519→  });
520→  if (generateEarly) { result = generateEarly; return result; }
521→
522→  // Phase 4: Deliver (degraded by default — delivery failures don't stop pipeline)
523→  metrics.startPhase('deliver');
524→  const publishGateEnabled = Boolean(fullConfig.publishGate?.enabled);
525→  const needsPublishReview = publishGateEnabled
526→    && (generateResult.data?.diagnostics?.publishGate?.needsReviewCount ?? 0) > 0;
527→
528→  // Filter out fallback briefs (placeholder content from API failures)
529→  const deliverableBriefs = (generateResult.data?.briefs ?? []).filter(
530→    (b) => !b.generationMeta?.isFallback
531→  );
532→
533→  const deliverResult = needsPublishReview
534→    ? {
535→      success: true,
536→      data: {
537→        subscriberCount: 0,
538→        sent: 0,
539→        failed: 0,
540→        dryRun: fullConfig.dryRun,
541→        skipped: true,
542→        skippedReason: 'publish_gate_review_required' as const,
543→      },
544→      duration: 0,
545→      phase: 'deliver' as const,
546→      timestamp: new Date(),
547→    }
548→    : deliverableBriefs.length
549→      ? await runDeliverPhase(runId, fullConfig, deliverableBriefs)
550→      : { success: true, data: { subscriberCount: 0, sent: 0, failed: 0, dryRun: fullConfig.dryRun }, duration: 0, phase: 'deliver' as const, timestamp: new Date() };
551→  metrics.completePhase('deliver', deliverResult.success, deliverResult.data?.sent || 0);
552→
553→  if (deliverResult.success) {
554→    await savePhaseResult(runId, 'deliver', deliverResult.data);
555→    const deliverOutcome = deliverResult.data?.skipped ? 'blocked' : 'completed';
556→    await updatePhaseStatus(runId, 'deliver', deliverOutcome);
557→    if (deliverResult.data) {
558→      await updatePhaseStats(runId, 'deliver', {
559→        sent: deliverResult.data.sent,
560→        failed: deliverResult.data.failed,
561→        subscriberCount: deliverResult.data.subscriberCount,
562→      });
563→    }
564→  } else {
565→    await updatePhaseStatus(runId, 'deliver', 'failed');
566→    errors.push({
567→      phase: 'deliver',
568→      message: deliverResult.error || 'Unknown error',
569→      timestamp: new Date(),
570→      recoverable: true,
571→      severity: deliverResult.severity ?? 'degraded',
572→    });
573→    captureException(
574→      new Error(deliverResult.error || 'Deliver phase failed'),
575→      { runId, phase: 'deliver', severity: deliverResult.severity ?? 'degraded' }
576→    );
577→    sendPipelineFailureAlert(runId, 'deliver', deliverResult.error || 'Unknown error', deliverResult.severity ?? 'degraded');
578→  }
579→
580→  const lockLossAfterDeliver = abortForLockLoss('deliver', {
581→    scrape: scrapeResult,
582→    analyze: analyzeResult,
583→    generate: generateResult,
584→    deliver: {
585→      ...deliverResult,
586→      success: false,
587→      error: 'Pipeline lock ownership lost during run',
588→    },
589→  });
590→  if (lockLossAfterDeliver) { result = lockLossAfterDeliver; return result; }
591→
592→  result = buildResult(
593→    runId,
594→    startedAt,
595→    fullConfig,
596→    {
597→      scrape: scrapeResult,
598→      analyze: analyzeResult,
599→      generate: generateResult,
600→      deliver: deliverResult,
601→    },
602→    errors
603→  );
604→
605→  // Attach API metrics to result
606→  const apiMetrics = getGlobalMetrics().getSummary();
607→  result.apiMetrics = apiMetrics;
608→
609→  const summary = metrics.getSummary();
610→  logger.info(
611→    { summary, success: result.success },
612→    'Pipeline completed'
613→  );
614→
615→  return result;
616→  } finally {
617→    // Finalize the pipeline run in the database. This is in `finally` so
618→    // the status update executes even if the process hit an unexpected
619→    // error (e.g. EPIPE) between buildResult and here.
620→    if (result) {
621→      try {
622→        const finalApiMetrics = result.apiMetrics ?? getGlobalMetrics().getSummary();
623→        const generationDiagnostics = buildGenerationDiagnosticsSnapshot(
624→          result.phases.generate,
625→          finalApiMetrics,
626→        );
627→
628→        const briefSummaries = result.phases.generate.data?.briefs?.map(b => ({
629→          id: b.id,
630→          name: b.name,
631→          tagline: b.tagline,
632→          priorityScore: b.priorityScore,
633→          effortEstimate: b.effortEstimate,
634→          generationMeta: b.generationMeta
635→            ? {
636→              isFallback: b.generationMeta.isFallback,
637→              fallbackReason: b.generationMeta.fallbackReason,
638→              providerMode: b.generationMeta.providerMode,
639→              graphAttemptCount: b.generationMeta.graphAttemptCount,
640→              graphModelsUsed: b.generationMeta.graphModelsUsed,
641→              graphFailedSections: b.generationMeta.graphFailedSections,
642→              graphRetriedSections: b.generationMeta.graphRetriedSections,
643→              graphTrace: b.generationMeta.graphTrace,
644→              handoffMeta: b.generationMeta.handoffMeta,
645→              publishDecision: b.generationMeta.publishDecision,
646→              publishConfidence: b.generationMeta.publishConfidence,
647→            }
648→            : null,
649→        })) || [];
650→
651→        const finalStatus = result.phases.deliver.data?.skipped
652→          ? 'needs_review'
653→          : result.success
654→            ? 'completed'
655→            : 'failed';
656→
657→        await db.update(pipelineRuns)
658→          .set({
659→            status: finalStatus,
660→            completedAt: result.completedAt,
661→            stats: result.stats,
662→            success: result.success,
663→            totalDuration: result.totalDuration,
664→            errors: result.errors,
665→            apiMetrics: finalApiMetrics || null,
666→            briefSummaries,
667→            generationMode: result.phases.generate.data?.generationMode ?? 'legacy',
668→            generationDiagnostics,
669→            updatedAt: new Date(),
670→          })
671→          .where(eq(pipelineRuns.runId, runId));
672→
673→        logger.info({ runId }, 'Pipeline run finalized in database');
674→      } catch (dbError) {
675→        logger.warn(
676→          { error: dbError instanceof Error ? dbError.message : String(dbError) },
677→          'Failed to finalize pipeline run in database (non-fatal)'
678→        );
679→      }
680→    }
681→
682→    stopLockHeartbeat?.();
683→    await releasePipelineLock(runId);
684→  }
685→}
