  1→/**
  2→ * ZeroToShip Scheduler
  3→ *
  4→ * Main entry point for the scheduler module.
  5→ * Provides cron-based scheduling and manual pipeline execution.
  6→ */
  7→
  8→import cron from 'node-cron';
  9→import { config as envConfig } from '../config/env';
 10→import { runPipeline, DEFAULT_PIPELINE_CONFIG } from './orchestrator';
 11→import { cleanupStaleRuns } from './utils/persistence';
 12→import { logger } from './utils/logger';
 13→import type { PipelineConfig, SchedulerConfig } from './types';
 14→
 15→const DEFAULT_SCHEDULER_CONFIG: SchedulerConfig = {
 16→  cronExpression: envConfig.SCHEDULER_CRON,
 17→  timezone: envConfig.SCHEDULER_TIMEZONE,
 18→  pipelineConfig: {
 19→    generationMode: envConfig.SCHEDULER_GENERATION_MODE ?? envConfig.GENERATION_MODE,
 20→  },
 21→  enabled: envConfig.SCHEDULER_ENABLED,
 22→};
 23→
 24→let scheduledTask: cron.ScheduledTask | null = null;
 25→
 26→/**
 27→ * Start the scheduler
 28→ */
 29→export async function startScheduler(config: Partial<SchedulerConfig> = {}): Promise<void> {
 30→  const fullConfig = {
 31→    ...DEFAULT_SCHEDULER_CONFIG,
 32→    ...config,
 33→    pipelineConfig: {
 34→      ...DEFAULT_SCHEDULER_CONFIG.pipelineConfig,
 35→      ...config.pipelineConfig,
 36→    },
 37→  };
 38→
 39→  if (!fullConfig.enabled) {
 40→    logger.info('Scheduler is disabled');
 41→    return;
 42→  }
 43→
 44→  if (!cron.validate(fullConfig.cronExpression)) {
 45→    logger.error(
 46→      { cronExpression: fullConfig.cronExpression },
 47→      'Invalid cron expression'
 48→    );
 49→    throw new Error(`Invalid cron expression: ${fullConfig.cronExpression}`);
 50→  }
 51→
 52→  logger.info(
 53→    { cronExpression: fullConfig.cronExpression, timezone: fullConfig.timezone },
 54→    'Starting scheduler'
 55→  );
 56→
 57→  // Clean up stale runs from previous crashes before scheduling new work
 58→  await cleanupStaleRuns();
 59→
 60→  scheduledTask = cron.schedule(
 61→    fullConfig.cronExpression,
 62→    async () => {
 63→      logger.info('Scheduled pipeline run triggered');
 64→      try {
 65→        const result = await runPipeline(fullConfig.pipelineConfig);
 66→        logger.info(
 67→          {
 68→            runId: result.runId,
 69→            success: result.success,
 70→            duration: result.totalDuration,
 71→          },
 72→          'Scheduled pipeline run completed'
 73→        );
 74→      } catch (error) {
 75→        logger.error({ error }, 'Scheduled pipeline run failed');
 76→      }
 77→    },
 78→    {
 79→      timezone: fullConfig.timezone,
 80→      scheduled: true,
 81→    }
 82→  );
 83→
 84→  logger.info('Scheduler started successfully');
 85→}
 86→
 87→/**
 88→ * Stop the scheduler
 89→ */
 90→export function stopScheduler(): void {
 91→  if (scheduledTask) {
 92→    scheduledTask.stop();
 93→    scheduledTask = null;
 94→    logger.info('Scheduler stopped');
 95→  }
 96→}
 97→
 98→/**
 99→ * Check if scheduler is running
100→ */
101→export function isSchedulerRunning(): boolean {
102→  return scheduledTask !== null;
103→}
