  3→/**
  4→ * ZeroToShip Scheduler CLI
  5→ *
  6→ * Command-line interface for running and managing the pipeline.
  7→ */
  8→
  9→import http from 'http';
 10→import { runPipeline } from './orchestrator';
 11→import { startScheduler, stopScheduler } from './index';
 12→import { checkPipelineFreshness } from './watchdog';
 13→import { closeDatabase } from '../api/db/client';
 14→import { processOnboardingDrip } from '../delivery/onboarding';
 15→import { logger } from './utils/logger';
 16→import type { PipelineConfig } from './types';
