 18→export interface CliOptions {
 19→  command: 'run' | 'schedule' | 'health' | 'onboarding-drip' | 'watchdog' | 'help';
 20→  dryRun: boolean;
 21→  hoursBack: number;
 22→  verbose: boolean;
 23→  maxBriefs: number;
 24→  maxAgeHours?: number;
 25→  generationMode?: 'legacy' | 'graph';
 26→}
 27→
 28→/**
 29→ * Parse command line arguments
 30→ */
 31→export function parseArgs(args: string[]): CliOptions {
 32→  const options: CliOptions = {
 33→    command: 'help',
 34→    dryRun: false,
 35→    hoursBack: 24,
 36→    verbose: false,
 37→    maxBriefs: 10,
 38→    maxAgeHours: undefined,
 39→  };
 40→
 41→  for (let i = 0; i < args.length; i++) {
 42→    const arg = args[i];
 43→
 44→    if (arg === 'run') options.command = 'run';
 45→    else if (arg === 'schedule') options.command = 'schedule';
 46→    else if (arg === 'health') options.command = 'health';
 47→    else if (arg === 'onboarding-drip') options.command = 'onboarding-drip';
 48→    else if (arg === 'watchdog') options.command = 'watchdog';
 49→    else if (arg === 'help' || arg === '--help' || arg === '-h')
 50→      options.command = 'help';
 51→    else if (arg === '--dry-run') options.dryRun = true;
 52→    else if (arg === '--verbose' || arg === '-v') options.verbose = true;
 53→    else if (arg === '--hours' && args[i + 1]) {
 54→      options.hoursBack = parseInt(args[++i], 10);
 55→    } else if (arg === '--max-briefs' && args[i + 1]) {
 56→      options.maxBriefs = parseInt(args[++i], 10);
 57→    } else if (arg === '--max-age-hours' && args[i + 1]) {
 58→      options.maxAgeHours = parseFloat(args[++i]);
 59→    } else if (arg === '--generation-mode' && args[i + 1]) {
 60→      const mode = args[++i];
 61→      if (mode === 'legacy' || mode === 'graph') {
 62→        options.generationMode = mode;
 63→      }
 64→    }
 65→  }
 66→
 67→  return options;
 68→}
