 70→/**
 71→ * Check environment health
 72→ */
 73→async function checkHealth(): Promise<boolean> {
 74→  const checks: { name: string; ok: boolean; message?: string }[] = [];
 75→
 76→  // Check required environment variables
 77→  const requiredEnvVars = ['OPENAI_API_KEY', 'RESEND_API_KEY'];
 78→  for (const envVar of requiredEnvVars) {
 79→    const value = process.env[envVar];
 80→    checks.push({
 81→      name: `ENV: ${envVar}`,
 82→      ok: !!value,
 83→      message: value ? 'Set' : 'Missing',
 84→    });
 85→  }
 86→
 87→  // Check optional environment variables
 88→  const optionalEnvVars = ['GITHUB_TOKEN', 'TWITTER_BEARER_TOKEN'];
 89→  for (const envVar of optionalEnvVars) {
 90→    const value = process.env[envVar];
 91→    checks.push({
 92→      name: `ENV: ${envVar} (optional)`,
 93→      ok: true, // Optional vars are always "ok"
 94→      message: value ? 'Set' : 'Not set',
 95→    });
 96→  }
 97→
 98→  console.log('\nHealth Check Results:');
 99→  console.log('='.repeat(50));
100→
101→  let allOk = true;
102→  for (const check of checks) {
103→    const status = check.ok ? '[OK]' : '[FAIL]';
104→    console.log(`${status} ${check.name}: ${check.message || ''}`);
105→    if (!check.ok) allOk = false;
106→  }
107→
108→  console.log('='.repeat(50));
109→  console.log(allOk ? '\nAll checks passed!' : '\nSome checks failed!');
110→
111→  return allOk;
112→}
