151→/**
152→ * Main CLI entry point
153→ */
154→async function main(): Promise<void> {
155→  // Ignore EPIPE errors on stdout/stderr — these occur when the parent
156→  // process (e.g. piped to `head`) closes before we finish writing.
157→  process.stdout.on('error', (err: NodeJS.ErrnoException) => {
158→    if (err.code === 'EPIPE') return;
159→    throw err;
160→  });
161→  process.stderr.on('error', (err: NodeJS.ErrnoException) => {
162→    if (err.code === 'EPIPE') return;
163→    throw err;
164→  });
165→
166→  const options = parseArgs(process.argv.slice(2));
167→
168→  if (options.verbose) {
169→    process.env.LOG_LEVEL = 'debug';
170→  }
171→
172→  switch (options.command) {
173→    case 'run': {
174→      console.log('Running ZeroToShip pipeline...\n');
175→
176→      const pipelineConfig: Partial<PipelineConfig> = {
177→        hoursBack: options.hoursBack,
178→        dryRun: options.dryRun,
179→        maxBriefs: options.maxBriefs,
180→        verbose: options.verbose,
181→        ...(options.generationMode && { generationMode: options.generationMode }),
182→      };
183→
184→      try {
185→        const result = await runPipeline(pipelineConfig);
186→
187→        console.log('\n' + '='.repeat(60));
188→        console.log('  PIPELINE RESULTS');
189→        console.log('='.repeat(60));
190→        console.log(`Run ID: ${result.runId}`);
191→        console.log(`Success: ${result.success}`);
192→        console.log(`Duration: ${(result.totalDuration / 1000).toFixed(1)}s`);
193→        console.log('\nPhase Summary:');
194→
195→        const phases = ['scrape', 'analyze', 'generate', 'deliver'] as const;
196→        for (const phase of phases) {
197→          const phaseResult = result.phases[phase];
198→          const status = phaseResult.success ? 'OK' : 'FAIL';
199→          console.log(
200→            `  ${phase}: [${status}] ${(phaseResult.duration / 1000).toFixed(1)}s`
201→          );
202→        }
203→
204→        console.log('\nStats:');
205→        console.log(`  Posts scraped: ${result.stats.postsScraped}`);
206→        console.log(`  Clusters created: ${result.stats.clustersCreated}`);
207→        console.log(`  Ideas generated: ${result.stats.ideasGenerated}`);
208→        console.log(`  Emails sent: ${result.stats.emailsSent}`);
209→
210→        if (result.errors.length > 0) {
211→          console.log('\nErrors:');
212→          for (const error of result.errors) {
213→            console.log(`  [${error.phase}] ${error.message}`);
214→          }
215→        }
216→
217→        if (!result.success) {
218→          await closeDatabase();
219→          process.exit(1);
220→        }
221→
222→        await closeDatabase();
223→        process.exit(0);
224→      } catch (error) {
225→        console.error('Pipeline failed:', error);
226→        await closeDatabase();
227→        process.exit(1);
228→      }
229→      break;
230→    }
231→
232→    case 'schedule': {
233→      console.log('Starting ZeroToShip scheduler...\n');
234→
235→      await startScheduler({
236→        pipelineConfig: {
237→          dryRun: options.dryRun,
238→          hoursBack: options.hoursBack,
239→          maxBriefs: options.maxBriefs,
240→          verbose: options.verbose,
241→          ...(options.generationMode && { generationMode: options.generationMode }),
242→        },
243→      });
244→
245→      // Minimal HTTP server so Railway keeps the container alive
246→      const port = parseInt(process.env.PORT || '8080', 10);
247→      const server = http.createServer((_req, res) => {
248→        res.writeHead(200, { 'Content-Type': 'application/json' });
249→        res.end(JSON.stringify({ status: 'ok', service: 'scheduler' }));
250→      });
251→      server.listen(port, () => {
252→        console.log(`Scheduler keepalive listening on port ${port}`);
253→      });
254→
255→      // Handle graceful shutdown
256→      process.on('SIGINT', () => {
257→        console.log('\nShutting down scheduler...');
258→        stopScheduler();
259→        server.close();
260→        process.exit(0);
261→      });
262→
263→      process.on('SIGTERM', () => {
264→        console.log('\nShutting down scheduler...');
265→        stopScheduler();
266→        server.close();
267→        process.exit(0);
268→      });
269→
270→      // Keep process running
271→      console.log('Scheduler is running. Press Ctrl+C to stop.\n');
272→      break;
273→    }
274→
275→    case 'onboarding-drip': {
276→      console.log('Processing onboarding drip emails...\n');
277→
278→      try {
279→        const dripResult = await processOnboardingDrip();
280→
281→        console.log('\n' + '='.repeat(60));
282→        console.log('  ONBOARDING DRIP RESULTS');
283→        console.log('='.repeat(60));
284→        console.log(`Processed: ${dripResult.processed}`);
285→        console.log(`Sent: ${dripResult.sent}`);
286→        console.log(`Skipped: ${dripResult.skipped}`);
287→        console.log(`Failed: ${dripResult.failed}`);
288→
289→        if (dripResult.details.length > 0) {
290→          console.log('\nDetails:');
291→          for (const detail of dripResult.details) {
292→            const status = detail.sent
293→              ? 'SENT'
294→              : detail.skipped
295→                ? 'SKIPPED'
296→                : 'FAILED';
297→            console.log(
298→              `  [${status}] ${detail.emailType} -> ${detail.userId}${detail.error ? ` (${detail.error})` : ''}`
299→            );
300→          }
301→        }
302→
303→        await closeDatabase();
304→        process.exit(0);
305→      } catch (error) {
306→        console.error('Onboarding drip failed:', error);
307→        await closeDatabase();
308→        process.exit(1);
309→      }
310→      break;
311→    }
312→
313→    case 'health': {
314→      const ok = await checkHealth();
315→      process.exit(ok ? 0 : 1);
316→    }
317→
318→    case 'watchdog': {
319→      console.log('Running pipeline watchdog check...\n');
320→
321→      try {
322→        const result = await checkPipelineFreshness({
323→          maxAgeHours: options.maxAgeHours,
324→          alertOnFailure: true,
325→        });
326→
327→        console.log('='.repeat(60));
328→        console.log('  PIPELINE WATCHDOG');
329→        console.log('='.repeat(60));
330→        console.log(`Healthy: ${result.healthy}`);
331→        console.log(`Reason: ${result.reason}`);
332→        console.log(`Checked at: ${result.checkedAt}`);
333→        console.log(`Threshold: ${result.maxAgeHours}h`);
334→        console.log(`Latest success age: ${result.ageHours ?? 'none'}h`);
335→        console.log(`Latest successful run: ${result.latestSuccessfulRunId || 'none'}`);
336→        console.log(`Latest run: ${result.latestRunId || 'none'} (${result.latestRunStatus || 'unknown'})`);
337→
338→        await closeDatabase();
339→        process.exit(result.healthy ? 0 : 1);
340→      } catch (error) {
341→        logger.error(
342→          { error: error instanceof Error ? error.message : String(error) },
343→          'Watchdog check failed'
344→        );
345→        await closeDatabase();
346→        process.exit(1);
347→      }
348→      break;
349→    }
350→
351→    case 'help':
352→    default:
353→      printHelp();
354→      break;
355→  }
356→}
357→
358→main().catch((error) => {
359→  console.error('Fatal error:', error);
360→  process.exit(1);
361→});
