  1→/**
  2→ * Deliver Phase Runner
  3→ *
  4→ * Sends daily brief emails to subscribers.
  5→ */
  6→
  7→import {
  8→  sendDailyBriefsBatch,
  9→  type Subscriber,
 10→} from '../../delivery/email';
 11→import { processOnboardingDrip } from '../../delivery/onboarding';
 12→import type { IdeaBrief } from '../../generation/brief-generator';
 13→import { createPhaseLogger } from '../utils/logger';
 14→import { DeliveryError, wrapError } from '../../lib/errors';
 15→import type {
 16→  PhaseResult,
 17→  DeliverPhaseOutput,
 18→  PipelineConfig,
 19→} from '../types';
 20→import { db, users, subscriptions, userPreferences, emailLogs } from '../../api/db/client';
 21→import { eq } from 'drizzle-orm';
 22→
 23→/**
 24→ * Get active subscribers from database
 25→ */
 26→async function getActiveSubscribers(): Promise<Subscriber[]> {
 27→  const rows = await db
 28→    .select({
 29→      id: users.id,
 30→      email: users.email,
 31→      tier: subscriptions.plan,
 32→      emailFrequency: userPreferences.emailFrequency,
 33→      unsubscribeToken: userPreferences.unsubscribeToken,
 34→    })
 35→    .from(users)
 36→    .innerJoin(subscriptions, eq(subscriptions.userId, users.id))
 37→    .leftJoin(userPreferences, eq(userPreferences.userId, users.id))
 38→    .where(eq(subscriptions.status, 'active'));
 39→
 40→  return rows
 41→    .filter((row) => row.emailFrequency !== 'never')
 42→    .map((row) => ({
 43→      id: row.id,
 44→      email: row.email,
 45→      tier: row.tier as Subscriber['tier'],
 46→      unsubscribeToken: row.unsubscribeToken ?? undefined,
 47→    }));
 48→}
 49→
 50→/**
 51→ * Run the deliver phase
 52→ */
 53→export async function runDeliverPhase(
 54→  runId: string,
 55→  config: PipelineConfig,
 56→  briefs: IdeaBrief[]
 57→): Promise<PhaseResult<DeliverPhaseOutput>> {
 58→  const logger = createPhaseLogger(runId, 'deliver');
 59→  const startTime = Date.now();
 60→
 61→  logger.info(
 62→    { briefCount: briefs.length, dryRun: config.dryRun },
 63→    'Starting deliver phase'
 64→  );
 65→
 66→  try {
 67→    if (config.dryRun) {
 68→      logger.info('Dry run mode - skipping actual email delivery');
 69→
 70→      // In dry run, just log what would be sent
 71→      const subscribers = await getActiveSubscribers();
 72→
 73→      return {
 74→        success: true,
 75→        data: {
 76→          subscriberCount: subscribers.length,
 77→          sent: 0,
 78→          failed: 0,
 79→          dryRun: true,
 80→        },
 81→        duration: Date.now() - startTime,
 82→        phase: 'deliver',
 83→        timestamp: new Date(),
 84→      };
 85→    }
 86→
 87→    // Get subscribers
 88→    const subscribers = await getActiveSubscribers();
 89→
 90→    if (subscribers.length === 0) {
 91→      logger.warn('No active subscribers found');
 92→      return {
 93→        success: true, // Not a failure, just nothing to do
 94→        data: {
 95→          subscriberCount: 0,
 96→          sent: 0,
 97→          failed: 0,
 98→          dryRun: false,
 99→        },
100→        duration: Date.now() - startTime,
101→        phase: 'deliver',
102→        timestamp: new Date(),
103→      };
104→    }
105→
106→    // Send emails
107→    const result = await sendDailyBriefsBatch(
108→      subscribers,
109→      briefs,
110→      {}, // Use default config
111→      {
112→        onProgress: (completed, total) => {
113→          logger.debug({ completed, total }, 'Delivery progress');
114→        },
115→      }
116→    );
117→
118→    // Persist delivery statuses to email_logs
119→    try {
120→      const emailLogRows = result.deliveries
121→        .filter((d) => d.status === 'sent' || d.status === 'failed')
122→        .map((delivery) => ({
123→          runId,
124→          userId: delivery.subscriberId,
125→          recipientEmail: delivery.email,
126→          subject: `Your Daily Startup Ideas — ${new Date().toLocaleDateString()}`,
127→          messageId: delivery.messageId,
128→          status: delivery.status as string,
129→          error: delivery.error || null,
130→          sentAt: delivery.sentAt,
131→        }));
132→
133→      if (emailLogRows.length > 0) {
134→        await db.insert(emailLogs).values(emailLogRows);
135→      }
136→    } catch (logError) {
137→      logger.warn(
138→        { error: logError instanceof Error ? logError.message : String(logError) },
139→        'Failed to persist email delivery logs (non-fatal)'
140→      );
141→    }
142→
143→    const duration = Date.now() - startTime;
144→
145→    // Process onboarding drip emails after daily digest
146→    try {
147→      const dripResult = await processOnboardingDrip();
148→      logger.info(
149→        {
150→          onboardingSent: dripResult.sent,
151→          onboardingSkipped: dripResult.skipped,
152→          onboardingFailed: dripResult.failed,
153→        },
154→        'Onboarding drip processing complete'
155→      );
156→    } catch (dripError) {
157→      // Onboarding drip failures should not fail the deliver phase
158→      logger.warn(
159→        { error: dripError instanceof Error ? dripError.message : String(dripError) },
160→        'Onboarding drip processing failed (non-fatal)'
161→      );
162→    }
163→
164→    logger.info(
165→      {
166→        subscriberCount: subscribers.length,
167→        sent: result.sent,
168→        failed: result.failed,
169→        duration,
170→      },
171→      'Deliver phase complete'
172→    );
173→
174→    return {
175→      success: result.failed === 0 || result.sent > 0,
176→      data: {
177→        subscriberCount: subscribers.length,
178→        sent: result.sent,
179→        failed: result.failed,
180→        dryRun: false,
181→      },
182→      duration,
183→      phase: 'deliver',
184→      timestamp: new Date(),
185→    };
186→  } catch (error) {
187→    const duration = Date.now() - startTime;
188→    const deliveryError = wrapError(error, DeliveryError);
189→    const errorMessage = deliveryError.message;
190→
191→    logger.error({ error: errorMessage, severity: deliveryError.severity }, 'Deliver phase failed');
192→
193→    return {
194→      success: false,
195→      data: null,
196→      error: errorMessage,
197→      severity: deliveryError.severity,
198→      duration,
199→      phase: 'deliver',
200→      timestamp: new Date(),
201→    };
202→  }
203→}
