  1→/**
  2→ * Email Delivery Service for ZeroToShip
  3→ *
  4→ * Sends daily brief emails to subscribers via Resend.
  5→ * Handles subscriber tiers and tracks delivery status.
  6→ */
  7→
  8→import type { IdeaBrief } from '../generation/brief-generator';
  9→import { config as envConfig } from '../config/env';
 10→import {
 11→  buildDailyEmail,
 12→  type SubscriberTier,
 13→  type EmailContent,
 14→  type EmailBuilderConfig,
 15→} from './email-builder';
 16→import { sendEmailWithRetry } from '../lib/resend';
 17→
 18→/** Send one email at a time — Resend free tier allows only 2 req/s and concurrent
 19→ *  sends + retries easily blow past that. Sequential is the only safe approach. */
 20→const DEFAULT_EMAIL_CONCURRENCY = 1;
 21→
 22→/** Delay between each email (ms) — 1 second keeps us well under the 2 req/s limit
 23→ *  even when a retry fires within the same window. */
 24→const DEFAULT_EMAIL_DELAY_MS = 1_000;
 25→
 26→/**
 27→ * Subscriber information
 28→ */
 29→export interface Subscriber {
 30→  id: string;
 31→  email: string;
 32→  tier: SubscriberTier;
 33→  unsubscribeToken?: string;
 34→}
 35→
 36→/**
 37→ * Delivery status for tracking
 38→ */
 39→export interface DeliveryStatus {
 40→  subscriberId: string;
 41→  email: string;
 42→  messageId: string | null;
 43→  status: 'sent' | 'failed' | 'bounced' | 'pending';
 44→  error?: string;
 45→  sentAt: Date;
 46→}
 47→
 48→/**
 49→ * Batch delivery result
 50→ */
 51→export interface BatchDeliveryResult {
 52→  total: number;
 53→  sent: number;
 54→  failed: number;
 55→  deliveries: DeliveryStatus[];
 56→}
 57→
 58→/**
 59→ * Email service configuration
 60→ */
 61→export interface EmailServiceConfig {
 62→  resendApiKey?: string;
 63→  fromEmail?: string;
 64→  fromName?: string;
 65→  replyTo?: string;
 66→  builderConfig?: EmailBuilderConfig;
 67→}
 68→
 69→const DEFAULT_CONFIG: Required<Omit<EmailServiceConfig, 'builderConfig'>> & {
 70→  builderConfig: EmailBuilderConfig;
 71→} = {
 72→  resendApiKey: '',
 73→  fromEmail: envConfig.RESEND_FROM_EMAIL || 'briefs@zerotoship.dev',
 74→  fromName: envConfig.RESEND_FROM_NAME || 'ZeroToShip',
 75→  replyTo: 'hello@zerotoship.dev',
 76→  builderConfig: {},
 77→};
 78→
 79→// sendViaResend is now centralized in src/lib/resend.ts as sendEmailWithRetry
 80→
 81→/**
 82→ * Build personalized unsubscribe URL for a subscriber
 83→ */
 84→function buildUnsubscribeUrl(baseUrl: string, subscriber: Subscriber): string | undefined {
 85→  if (!subscriber.unsubscribeToken) {
 86→    return undefined;
 87→  }
 88→  return `${baseUrl}/unsubscribe?token=${encodeURIComponent(subscriber.unsubscribeToken)}`;
 89→}
 90→
 91→/**
 92→ * Send daily brief email to a single subscriber
 93→ */
 94→export async function sendDailyBrief(
 95→  subscriber: Subscriber,
 96→  briefs: IdeaBrief[],
 97→  config: EmailServiceConfig = {}
 98→): Promise<DeliveryStatus> {
 99→  const opts = { ...DEFAULT_CONFIG, ...config };
100→
101→  const status: DeliveryStatus = {
102→    subscriberId: subscriber.id,
103→    email: subscriber.email,
104→    messageId: null,
105→    status: 'pending',
106→    sentAt: new Date(),
107→  };
108→
109→  // Build personalized email content
110→  const tokenUrl = buildUnsubscribeUrl(
111→    opts.builderConfig?.baseUrl || 'https://zerotoship.dev',
112→    subscriber
113→  );
114→  const builderConfig: EmailBuilderConfig = {
115→    ...opts.builderConfig,
116→    ...(tokenUrl ? { unsubscribeUrl: tokenUrl } : {}),
117→  };
118→
119→  const emailContent = buildDailyEmail(briefs, subscriber.tier, builderConfig);
120→
121→  // Send via centralized Resend client (with 3x retry)
122→  const from = `${opts.fromName} <${opts.fromEmail}>`;
123→  const result = await sendEmailWithRetry({
124→    to: subscriber.email,
125→    subject: emailContent.subject,
126→    html: emailContent.html,
127→    text: emailContent.text,
128→    from,
129→    replyTo: opts.replyTo,
130→  });
131→
132→  if (result.success) {
133→    status.status = 'sent';
134→    status.messageId = result.messageId || null;
135→  } else {
136→    status.status = 'failed';
137→    status.error = result.error;
138→  }
139→
140→  return status;
141→}
142→
143→/**
144→ * Send daily briefs to multiple subscribers
145→ */
146→export async function sendDailyBriefsBatch(
147→  subscribers: Subscriber[],
148→  briefs: IdeaBrief[],
149→  config: EmailServiceConfig = {},
150→  options: {
151→    concurrency?: number;
152→    delayMs?: number;
153→    onProgress?: (completed: number, total: number) => void;
154→  } = {}
155→): Promise<BatchDeliveryResult> {
156→  const { concurrency = DEFAULT_EMAIL_CONCURRENCY, delayMs = DEFAULT_EMAIL_DELAY_MS, onProgress } = options;
157→
158→  const result: BatchDeliveryResult = {
159→    total: subscribers.length,
160→    sent: 0,
161→    failed: 0,
162→    deliveries: [],
163→  };
164→
165→  if (subscribers.length === 0) {
166→    return result;
167→  }
168→
169→  // Process in batches
170→  for (let i = 0; i < subscribers.length; i += concurrency) {
171→    const batch = subscribers.slice(i, i + concurrency);
172→
173→    const batchPromises = batch.map(subscriber =>
174→      sendDailyBrief(subscriber, briefs, config)
175→    );
176→
177→    const batchResults = await Promise.all(batchPromises);
178→
179→    for (const delivery of batchResults) {
180→      result.deliveries.push(delivery);
181→      if (delivery.status === 'sent') {
182→        result.sent++;
183→      } else {
184→        result.failed++;
185→      }
186→    }
187→
188→    // Progress callback
189→    if (onProgress) {
190→      const completed = Math.min(i + concurrency, subscribers.length);
191→      onProgress(completed, subscribers.length);
192→    }
193→
194→    // Rate limiting delay between batches
195→    if (i + concurrency < subscribers.length && delayMs > 0) {
196→      await new Promise(resolve => setTimeout(resolve, delayMs));
197→    }
198→  }
199→
200→  return result;
201→}
202→
203→/**
204→ * Preview email without sending (for testing)
205→ */
206→export function previewDailyBrief(
207→  tier: SubscriberTier,
208→  briefs: IdeaBrief[],
209→  config: EmailBuilderConfig = {}
210→): EmailContent {
211→  return buildDailyEmail(briefs, tier, config);
212→}
213→
214→/**
215→ * Validate email address format
216→ */
217→export function isValidEmail(email: string): boolean {
218→  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
219→  return emailRegex.test(email);
220→}
221→
222→/**
223→ * Filter failed deliveries for retry
224→ */
225→export function getFailedDeliveries(result: BatchDeliveryResult): DeliveryStatus[] {
226→  return result.deliveries.filter(d => d.status === 'failed');
227→}
228→
229→/**
230→ * Get delivery statistics
231→ */
232→export function getDeliveryStats(result: BatchDeliveryResult): {
233→  successRate: number;
234→  failureRate: number;
235→  averagePerSecond: number;
236→} {
237→  const successRate = result.total > 0 ? (result.sent / result.total) * 100 : 0;
238→  const failureRate = result.total > 0 ? (result.failed / result.total) * 100 : 0;
239→
240→  // Estimate delivery rate (concurrency * 1000 / delayMs)
241→  const ESTIMATED_EMAILS_PER_SECOND = DEFAULT_EMAIL_CONCURRENCY * (1000 / DEFAULT_EMAIL_DELAY_MS);
242→  const averagePerSecond = result.total > 0 ? ESTIMATED_EMAILS_PER_SECOND : 0;
243→
244→  return {
245→    successRate,
246→    failureRate,
247→    averagePerSecond,
248→  };
249→}
250→
251→/**
252→ * Create a test subscriber for development
253→ */
254→export function createTestSubscriber(
255→  email: string,
256→  tier: SubscriberTier = 'free'
257→): Subscriber {
258→  return {
259→    id: `test_${Date.now()}`,
260→    email,
261→    tier,
262→    unsubscribeToken: `unsub_${Date.now()}`,
263→  };
264→}
