  1→/**
  2→ * Scrape Phase Runner
  3→ *
  4→ * Runs all enabled scrapers in parallel and combines results.
  5→ */
  6→
  7→import type { RawPost, HNPost, Tweet, GitHubIssue } from '../../scrapers/types';
  8→import { scrapeReddit, DEFAULT_SUBREDDITS } from '../../scrapers/reddit';
  9→import { scrapeHackerNews } from '../../scrapers/hackernews';
 10→import { twitterScraper } from '../../scrapers/twitter';
 11→import { scrapeGitHub } from '../../scrapers/github';
 12→import { createPhaseLogger } from '../utils/logger';
 13→import { withRetry } from '../utils/retry';
 14→import { ScraperError, wrapError } from '../../lib/errors';
 15→import type {
 16→  PhaseResult,
 17→  ScrapePhaseOutput,
 18→  PipelineConfig,
 19→} from '../types';
 20→
 21→interface ScraperResult {
 22→  name: 'reddit' | 'hn' | 'twitter' | 'github';
 23→  posts: RawPost[];
 24→  success: boolean;
 25→  error?: string;
 26→}
 27→
 28→/**
 29→ * Run a single scraper with retry logic
 30→ */
 31→async function runScraper<T extends RawPost>(
 32→  name: 'reddit' | 'hn' | 'twitter' | 'github',
 33→  scraperFn: () => Promise<T[]>
 34→): Promise<ScraperResult> {
 35→  try {
 36→    const posts = await withRetry(scraperFn, { maxAttempts: 2 }, `scraper:${name}`);
 37→    return { name, posts, success: true };
 38→  } catch (error) {
