  1→/**
  2→ * Pipeline Watchdog
  3→ *
  4→ * Detects stale daily runs by checking when the last successful run completed.
  5→ * When stale, it triggers a missed-run alert.
  6→ */
  7→
  8→import { desc, eq } from 'drizzle-orm';
  9→import { db, pipelineRuns } from '../api/db/client';
 10→import { config } from '../config/env';
 11→import { sendPipelineMissedRunAlert } from '../lib/alerts';
 12→import { createLogger } from './utils/logger';
 13→
 14→const logger = createLogger({ context: 'pipeline-watchdog' });
 15→
 16→const HOURS_TO_MS = 60 * 60 * 1000;
 17→
 18→export interface WatchdogOptions {
 19→  maxAgeHours?: number;
 20→  alertOnFailure?: boolean;
 21→  now?: Date;
 22→}
 23→
 24→export interface WatchdogResult {
 25→  healthy: boolean;
 26→  reason: string;
 27→  checkedAt: string;
 28→  maxAgeHours: number;
 29→  ageHours: number | null;
 30→  latestSuccessfulRunId: string | null;
 31→  latestSuccessfulCompletedAt: string | null;
 32→  latestRunId: string | null;
 33→  latestRunStatus: string | null;
 34→}
 35→
 36→/**
 37→ * Check whether the pipeline has completed a successful run recently enough.
 38→ */
 39→export async function checkPipelineFreshness(
 40→  options: WatchdogOptions = {}
 41→): Promise<WatchdogResult> {
 42→  const maxAgeHours = options.maxAgeHours ?? config.WATCHDOG_MAX_SUCCESS_AGE_HOURS;
 43→  const alertOnFailure = options.alertOnFailure ?? true;
 44→  const now = options.now ?? new Date();
 45→
 46→  const [successfulRows, latestRows] = await Promise.all([
 47→    db
 48→      .select({
 49→        runId: pipelineRuns.runId,
 50→        startedAt: pipelineRuns.startedAt,
 51→        completedAt: pipelineRuns.completedAt,
 52→      })
 53→      .from(pipelineRuns)
 54→      .where(eq(pipelineRuns.success, true))
 55→      .orderBy(desc(pipelineRuns.startedAt))
 56→      .limit(1),
 57→    db
 58→      .select({
 59→        runId: pipelineRuns.runId,
 60→        status: pipelineRuns.status,
 61→        startedAt: pipelineRuns.startedAt,
 62→        completedAt: pipelineRuns.completedAt,
 63→      })
 64→      .from(pipelineRuns)
 65→      .orderBy(desc(pipelineRuns.startedAt))
 66→      .limit(1),
 67→  ]);
 68→
 69→  const latestSuccessfulRun = successfulRows[0];
 70→  const latestRun = latestRows[0];
 71→  const latestSuccessTime = latestSuccessfulRun?.completedAt || latestSuccessfulRun?.startedAt || null;
 72→  const ageHours = latestSuccessTime
 73→    ? (now.getTime() - latestSuccessTime.getTime()) / HOURS_TO_MS
 74→    : null;
 75→  const healthy = ageHours !== null && ageHours <= maxAgeHours;
 76→
 77→  const result: WatchdogResult = {
 78→    healthy,
 79→    reason: healthy
 80→      ? `Latest successful run is within threshold (${ageHours!.toFixed(2)}h <= ${maxAgeHours}h)`
 81→      : latestSuccessfulRun
 82→        ? `Latest successful run is stale (${ageHours!.toFixed(2)}h > ${maxAgeHours}h)`
 83→        : 'No successful pipeline run found',
 84→    checkedAt: now.toISOString(),
 85→    maxAgeHours,
 86→    ageHours: ageHours !== null ? Number(ageHours.toFixed(2)) : null,
 87→    latestSuccessfulRunId: latestSuccessfulRun?.runId ?? null,
 88→    latestSuccessfulCompletedAt: latestSuccessTime?.toISOString() ?? null,
 89→    latestRunId: latestRun?.runId ?? null,
 90→    latestRunStatus: latestRun?.status ?? null,
 91→  };
 92→
 93→  if (healthy) {
 94→    logger.info(
 95→      {
 96→        maxAgeHours,
 97→        ageHours: result.ageHours,
 98→        latestSuccessfulRunId: result.latestSuccessfulRunId,
 99→      },
100→      'Pipeline watchdog check passed'
101→    );
102→    return result;
103→  }
104→
105→  logger.error(
106→    {
107→      maxAgeHours,
108→      ageHours: result.ageHours,
109→      latestSuccessfulRunId: result.latestSuccessfulRunId,
110→      latestRunId: result.latestRunId,
111→      latestRunStatus: result.latestRunStatus,
112→    },
113→    'Pipeline watchdog detected stale or missing successful run'
114→  );
115→
116→  if (alertOnFailure) {
117→    await sendPipelineMissedRunAlert({
118→      maxAgeHours,
119→      ageHours: ageHours ?? maxAgeHours + 1,
120→      latestSuccessfulRunId: result.latestSuccessfulRunId ?? undefined,
121→      latestSuccessfulCompletedAt: result.latestSuccessfulCompletedAt ?? undefined,
122→      latestRunId: result.latestRunId ?? undefined,
123→      latestRunStatus: result.latestRunStatus ?? undefined,
124→    });
125→  }
126→
127→  return result;
128→}
