  1→/**
  2→ * Pipeline Run Persistence
  3→ *
  4→ * Persists phase results to the database so a failed pipeline can resume
  5→ * from the last completed phase instead of starting from scratch.
  6→ *
  7→ * Uses the `pipeline_runs` table as the single source of truth.
  8→ */
  9→
 10→import { eq, and, lt, sql } from 'drizzle-orm';
 11→import { createLogger } from './logger';
 12→import { db, pipelineRuns } from '../../api/db/client';
 13→import type { PhaseName, PipelineConfig } from '../types';
 14→
 15→const logger = createLogger({ context: 'persistence' });
 16→
 17→/**
 18→ * Summary stats for each pipeline phase, persisted alongside status
 19→ */
 20→export interface PhaseStats {
 21→  scrape?: { totalPosts: number; reddit: number; hn: number; twitter: number; github: number };
 22→  analyze?: { clusterCount: number; scoredCount: number; gapAnalysisCount: number };
 23→  generate?: { briefCount: number };
 24→  deliver?: { sent: number; failed: number; subscriberCount: number };
 25→}
 26→
 27→/**
 28→ * Status of each phase within a persisted run
 29→ */
 30→export interface RunStatus {
 31→  runId: string;
 32→  config: PipelineConfig;
 33→  startedAt: string;
 34→  phases: Record<PhaseName, 'pending' | 'completed' | 'failed' | 'blocked'>;
 35→  phaseStats?: PhaseStats;
 36→  lastCompletedPhase: PhaseName | null;
 37→  updatedAt: string;
 38→}
 39→
 40→/**
 41→ * Custom JSON replacer that handles Map instances.
 42→ * Converts Map to a serializable format: { __type: 'Map', entries: [...] }
 43→ */
 44→function jsonReplacer(_key: string, value: unknown): unknown {
 45→  if (value instanceof Map) {
 46→    return {
 47→      __type: 'Map',
 48→      entries: Array.from(value.entries()),
 49→    };
 50→  }
 51→  return value;
 52→}
 53→
 54→/**
 55→ * Custom JSON reviver that restores Map instances.
 56→ */
 57→function jsonReviver(_key: string, value: unknown): unknown {
 58→  if (
 59→    value &&
 60→    typeof value === 'object' &&
 61→    (value as Record<string, unknown>).__type === 'Map' &&
 62→    Array.isArray((value as Record<string, unknown>).entries)
 63→  ) {
 64→    return new Map((value as { entries: [string, unknown][] }).entries);
 65→  }
 66→  return value;
 67→}
 68→
 69→/**
 70→ * Serialize data for JSONB storage, handling Map instances.
 71→ */
 72→function serializeForJsonb(data: unknown): unknown {
 73→  return JSON.parse(JSON.stringify(data, jsonReplacer));
 74→}
 75→
 76→/**
 77→ * Deserialize data from JSONB storage, restoring Map instances.
 78→ */
 79→function deserializeFromJsonb<T>(data: unknown): T {
 80→  return JSON.parse(JSON.stringify(data), jsonReviver) as T;
 81→}
