100→    phases,
101→    stats: { postsScraped: 0, clustersCreated: 0, ideasGenerated: 0, emailsSent: 0 },
102→    phaseResults: {},
103→    phaseStats: {},
104→    generationDiagnostics: null,
105→    lastCompletedPhase: null,
106→    success: false,
107→    updatedAt: new Date(),
108→  });
