113→/**
114→ * Persist phase output data to the database
115→ */
116→export async function savePhaseResult(
117→  runId: string,
118→  phase: PhaseName,
119→  data: unknown
120→): Promise<void> {
121→  const row = await db.select({ phaseResults: pipelineRuns.phaseResults })
122→    .from(pipelineRuns)
123→    .where(eq(pipelineRuns.runId, runId))
124→    .limit(1);
125→
126→  if (row.length === 0) {
127→    logger.warn({ runId }, 'Cannot save phase result: run not found in database');
128→    return;
129→  }
130→
131→  const existing = (row[0].phaseResults as Record<string, unknown>) || {};
132→  existing[phase] = serializeForJsonb(data);
133→
134→  await db.update(pipelineRuns)
135→    .set({ phaseResults: existing, updatedAt: new Date() })
136→    .where(eq(pipelineRuns.runId, runId));
137→
138→  logger.debug({ runId, phase }, 'Saved phase result to database');
139→}
