141→/**
142→ * Update the run status after a phase completes or fails
143→ */
144→export async function updatePhaseStatus(
145→  runId: string,
146→  phase: PhaseName,
147→  outcome: 'completed' | 'failed' | 'blocked'
148→): Promise<void> {
149→  const row = await db.select({
150→    phases: pipelineRuns.phases,
151→    lastCompletedPhase: pipelineRuns.lastCompletedPhase,
152→  })
153→    .from(pipelineRuns)
154→    .where(eq(pipelineRuns.runId, runId))
155→    .limit(1);
156→
157→  if (row.length === 0) {
158→    logger.warn({ runId }, 'Cannot update status: run not found in database');
159→    return;
160→  }
161→
162→  const phases = row[0].phases as Record<PhaseName, 'pending' | 'completed' | 'failed' | 'blocked'>;
163→  phases[phase] = outcome;
164→
165→  const updates: Record<string, unknown> = {
166→    phases,
167→    updatedAt: new Date(),
168→  };
169→
170→  if (outcome === 'completed') {
171→    updates.lastCompletedPhase = phase;
172→  }
173→
174→  await db.update(pipelineRuns)
175→    .set(updates)
176→    .where(eq(pipelineRuns.runId, runId));
177→
178→  logger.debug({ runId, phase, outcome }, 'Updated phase status in database');
179→}
