181→/**
182→ * Update phase stats in the database
183→ */
184→export async function updatePhaseStats(
185→  runId: string,
186→  phase: PhaseName,
187→  stats: PhaseStats[keyof PhaseStats]
188→): Promise<void> {
189→  const row = await db.select({ phaseStats: pipelineRuns.phaseStats })
190→    .from(pipelineRuns)
191→    .where(eq(pipelineRuns.runId, runId))
192→    .limit(1);
193→
194→  if (row.length === 0) {
195→    logger.warn({ runId }, 'Cannot update phase stats: run not found in database');
196→    return;
197→  }
198→
199→  const existing = (row[0].phaseStats as Record<string, unknown>) || {};
200→  existing[phase] = stats;
201→
202→  await db.update(pipelineRuns)
203→    .set({ phaseStats: existing, updatedAt: new Date() })
204→    .where(eq(pipelineRuns.runId, runId));
205→
206→  logger.debug({ runId, phase }, 'Updated phase stats in database');
207→}
