209→/**
210→ * Load the run status from the database. Returns null if not found.
211→ */
212→export async function loadRunStatus(runId: string): Promise<RunStatus | null> {
213→  try {
214→    const row = await db.select()
215→      .from(pipelineRuns)
216→      .where(eq(pipelineRuns.runId, runId))
217→      .limit(1);
218→
219→    if (row.length === 0) {
220→      return null;
221→    }
222→
223→    const run = row[0];
224→    return {
225→      runId: run.runId,
226→      config: run.config as PipelineConfig,
227→      startedAt: run.startedAt.toISOString(),
228→      phases: run.phases as Record<PhaseName, 'pending' | 'completed' | 'failed'>,
229→      phaseStats: (run.phaseStats as PhaseStats) || undefined,
230→      lastCompletedPhase: (run.lastCompletedPhase as PhaseName) || null,
231→      updatedAt: run.updatedAt.toISOString(),
232→    };
233→  } catch (err) {
234→    logger.warn(
235→      { runId, error: err instanceof Error ? err.message : String(err) },
236→      'Failed to load run status from database'
237→    );
238→    return null;
239→  }
240→}
