242→/**
243→ * Load persisted phase output from the database. Returns null if not found.
244→ */
245→export async function loadPhaseResult<T>(runId: string, phase: PhaseName): Promise<T | null> {
246→  try {
247→    const row = await db.select({ phaseResults: pipelineRuns.phaseResults })
248→      .from(pipelineRuns)
249→      .where(eq(pipelineRuns.runId, runId))
250→      .limit(1);
251→
252→    if (row.length === 0) {
253→      return null;
254→    }
255→
256→    const phaseResults = row[0].phaseResults as Record<string, unknown> | null;
257→    if (!phaseResults || !(phase in phaseResults)) {
258→      return null;
259→    }
260→
261→    return deserializeFromJsonb<T>(phaseResults[phase]);
262→  } catch (err) {
263→    logger.warn(
264→      { runId, phase, error: err instanceof Error ? err.message : String(err) },
265→      'Failed to load phase result from database'
266→    );
267→    return null;
268→  }
269→}
