271→/**
272→ * Determine which phase to resume from, given a run's status.
273→ * Returns the first phase that is not 'completed', or null if all are done.
274→ */
275→export function getResumePhase(status: RunStatus): PhaseName | null {
276→  const phaseOrder: PhaseName[] = ['scrape', 'analyze', 'generate', 'deliver'];
277→
278→  for (const phase of phaseOrder) {
279→    if (status.phases[phase] !== 'completed') {
280→      return phase;
281→    }
282→  }
283→
284→  return null;
285→}
286→
287→/** Max age (in hours) before a `running` row is considered stale and marked `failed`. */
288→const STALE_RUN_THRESHOLD_HOURS = 4;
289→
290→/**
291→ * Mark stale `running` rows as `failed`.
292→ *
293→ * A run is considered stale if its `startedAt` is older than the threshold
294→ * and it still has status `running`. This is a safety net — if the process
295→ * crashed and never finalized the row, this prevents it from blocking future
296→ * runs or confusing the dashboard.
297→ *
298→ * Call at the start of `runPipeline()` before acquiring the lock.
299→ */
300→export async function cleanupStaleRuns(): Promise<number> {
301→  try {
302→    const cutoff = new Date(Date.now() - STALE_RUN_THRESHOLD_HOURS * 60 * 60 * 1000);
303→    const result = await db.update(pipelineRuns)
304→      .set({
305→        status: 'failed',
306→        success: false,
307→        errors: sql`COALESCE(${pipelineRuns.errors}, '[]'::jsonb) || ${JSON.stringify([{
308→          phase: 'scrape',
309→          message: `Marked as failed by stale-run cleanup (running for >${STALE_RUN_THRESHOLD_HOURS}h)`,
310→          timestamp: new Date().toISOString(),
311→          recoverable: false,
312→          severity: 'fatal',
313→        }])}::jsonb`,
314→        updatedAt: new Date(),
315→      })
316→      .where(
317→        and(
318→          eq(pipelineRuns.status, 'running'),
319→          lt(pipelineRuns.startedAt, cutoff),
320→        )
321→      )
322→      .returning({ runId: pipelineRuns.runId });
323→
324→    if (result.length > 0) {
325→      logger.warn(
326→        { count: result.length, runIds: result.map(r => r.runId) },
327→        'Cleaned up stale running pipeline rows'
328→      );
329→    }
330→
331→    return result.length;
332→  } catch (err) {
333→    logger.warn(
334→      { error: err instanceof Error ? err.message : String(err) },
335→      'Failed to clean up stale runs (non-fatal)'
336→    );
337→    return 0;
338→  }
339→}
