 60→    return crypto.createHash('sha256').update(url.trim().toLowerCase()).digest('hex').slice(0, 16);
 61→  }
 62→  return crypto.createHash('sha256').update(problemStatement.trim()).digest('hex').slice(0, 16);
 63→}
 64→
 65→/**
 66→ * Get the cache file path
 67→ */
 68→function getCacheFilePath(cacheDir: string): string {
 69→  return path.join(cacheDir, 'scores.json');
 70→}
 71→
 72→/**
 73→ * Load the cache from disk. Returns empty cache if not found or corrupted.
 74→ */
 75→function loadCache(cacheDir: string): CacheFile {
 76→  const filePath = getCacheFilePath(cacheDir);
 77→  try {
 78→    if (!fs.existsSync(filePath)) {
 79→      return { version: 3, entries: {} };
 80→    }
 81→    const raw = fs.readFileSync(filePath, 'utf-8');
 82→    const data = JSON.parse(raw) as CacheFile;
 83→    if (data.version !== 3 || typeof data.entries !== 'object') {
 84→      logger.warn('Score cache file has invalid format, resetting');
 85→      return { version: 3, entries: {} };
 86→    }
 87→    return data;
 88→  } catch (err) {
 89→    logger.warn(
 90→      { error: err instanceof Error ? err.message : String(err) },
 91→      'Failed to load score cache, starting fresh'
 92→    );
 93→    return { version: 3, entries: {} };
 94→  }
 95→}
 96→
 97→/**
 98→ * Save the cache to disk
 99→ */
100→function saveCache(cacheDir: string, cache: CacheFile): void {
101→  try {
102→    fs.mkdirSync(cacheDir, { recursive: true });
103→    const filePath = getCacheFilePath(cacheDir);
104→    fs.writeFileSync(filePath, JSON.stringify(cache, null, 2), 'utf-8');
105→  } catch (err) {
106→    logger.warn(
107→      { error: err instanceof Error ? err.message : String(err) },
108→      'Failed to save score cache'
109→    );
110→  }
111→}
112→
113→/**
114→ * Check if a cache entry is still valid (within TTL)
115→ */
116→function isEntryValid(entry: CacheEntry, ttlMs: number): boolean {
117→  const cachedAt = new Date(entry.cachedAt).getTime();
118→  return Date.now() - cachedAt < ttlMs;
119→}
120→
121→/**
122→ * Score Cache class
123→ *
124→ * Provides lookup and storage of scored problems keyed by post URL
125→ * or problem statement hash.
126→ */
127→export class ScoreCache {
128→  private cache: CacheFile;
129→  private cacheDir: string;
130→  private ttlMs: number;
131→  private disabled: boolean;
132→
133→  constructor(options: ScoreCacheOptions = {}) {
134→    this.cacheDir = options.cacheDir || CACHE_DIR;
135→    this.ttlMs = options.ttlMs ?? DEFAULT_TTL_MS;
136→    this.disabled = options.disabled ?? false;
137→    this.cache = this.disabled ? { version: 3, entries: {} } : loadCache(this.cacheDir);
138→  }
139→
140→  /**
141→   * Look up a cached score by post URL or problem statement.
142→   * Returns the ScoredProblem if found and still within TTL, otherwise null.
143→   */
144→  get(url: string | undefined, problemStatement: string): ScoredProblem | null {
145→    if (this.disabled) return null;
146→
147→    const key = getCacheKey(url, problemStatement);
148→    const entry = this.cache.entries[key];
149→
150→    if (!entry) return null;
151→    if (!isEntryValid(entry, this.ttlMs)) {
152→      delete this.cache.entries[key];
153→      return null;
154→    }
155→
156→    // Restore Date objects that were serialized
157→    const sp = entry.scoredProblem;
158→    sp.representativePost.createdAt = new Date(sp.representativePost.createdAt);
159→    sp.representativePost.scrapedAt = new Date(sp.representativePost.scrapedAt);
160→    for (const post of sp.relatedPosts) {
161→      post.createdAt = new Date(post.createdAt);
162→      post.scrapedAt = new Date(post.scrapedAt);
163→    }
164→
165→    return sp;
166→  }
167→
168→  /**
169→   * Store a scored problem in the cache.
170→   */
171→  set(scoredProblem: ScoredProblem): void {
172→    if (this.disabled) return;
173→
174→    const url = scoredProblem.representativePost.url;
175→    const key = getCacheKey(url, scoredProblem.problemStatement);
176→
177→    this.cache.entries[key] = {
178→      scoredProblem,
179→      cachedAt: new Date().toISOString(),
180→    };
181→  }
182→
183→  /**
184→   * Persist the cache to disk. Call after a scoring run completes.
185→   */
186→  save(): void {
187→    if (this.disabled) return;
188→    this.pruneExpired();
189→    saveCache(this.cacheDir, this.cache);
190→  }
191→
192→  /**
193→   * Remove expired entries from the cache
194→   */
195→  pruneExpired(): void {
196→    for (const [key, entry] of Object.entries(this.cache.entries)) {
197→      if (!isEntryValid(entry, this.ttlMs)) {
198→        delete this.cache.entries[key];
199→      }
200→    }
201→  }
202→
203→  /**
204→   * Get statistics about the cache
205→   */
206→  stats(): { totalEntries: number; validEntries: number; expiredEntries: number } {
207→    let valid = 0;
208→    let expired = 0;
209→    for (const entry of Object.values(this.cache.entries)) {
210→      if (isEntryValid(entry, this.ttlMs)) {
211→        valid++;
212→      } else {
213→        expired++;
214→      }
215→    }
216→    return { totalEntries: valid + expired, validEntries: valid, expiredEntries: expired };
217→  }
218→
219→  /**
220→   * Clear all cache entries
221→   */
222→  clear(): void {
223→    this.cache.entries = {};
224→  }
225→}
