 46→    marketSize: row.marketSize || undefined,
 47→
 48→    existingSolutions: row.existingSolutions || undefined,
 49→    gaps: row.gaps || undefined,
 50→
 51→    proposedSolution: row.proposedSolution || undefined,
 52→    keyFeatures: (row.keyFeatures as string[]) || undefined,
 53→    mvpScope: row.mvpScope || undefined,
 54→
 55→    technicalSpec: row.technicalSpec as IdeaBrief['technicalSpec'],
 56→    businessModel: row.businessModel as IdeaBrief['businessModel'],
 57→    goToMarket: row.goToMarket as IdeaBrief['goToMarket'],
 58→
 59→    risks: (row.risks as string[]) || undefined,
 60→    sources: (row.sources as IdeaBrief['sources']) || [],
 61→    generatedAt: row.generatedAt.toISOString(),
 62→  };
 63→}
